mapper.select:
SELECT t2.*,
IF(t2.locker is not null and t2.locker = #{vo.curOperator}, 1,0) isSelf,
IF(t2.locker is null and t2.back_content is null, 1,0) unlocked,
IF(t2.back_content  is null or t2.back_content , 1, 0) back
FROM site_user_feedback t1
JOIN site_user_feedback t2 ON t1.feed_id = t2.id and t1.sort = 0

    t1.site_code = #{siteCode}

        AND t2.user_account like CONCAT('%',#{vo.userAccount}, '%')


        AND t2.back_account like CONCAT('%',#{vo.operator}, '%')


        AND t2.vip_grade_code = #{vo.vipGradeCode}


        AND t2.lock_status = #{vo.lockStatus}


        AND t2.type = #{vo.type}




        ORDER BY ${vo.orderField} ${vo.orderType}


        order BY isSelf desc, unlocked desc, back desc, updated_time desc


        order BY is_read asc, updated_time desc,created_time desc
